import{S as r,i as c,s as i,j as l,m,o as p,E as u,x as f,u as g,v as d}from"./vendor-ea8ed43c.js";import{S as _,a as $}from"./iconographySetup-4e8e8521.js";import{d as s}from"./index-d573ac81.js";import"./linear-a465d416.js";import"./preload-helper-1153c41b.js";function z(o){let e,a,ttl="浴牛感恩祈畜旺",src="";if(o[2]==="tezca2"){ttl="物候时令定农时";src=""}else if(o[2]==="tezca3"){ttl="春祈秋报告土地";src=""}return e=new _({props:{title:ttl,source:src,sourceUrl:s.source_tezca_url,name:o[2],imgPath:o[3],selected:0,steps:o[1],positions:$,imageRange:o[0]}}),{c(){l(e.$$.fragment)},l(t){m(e.$$.fragment,t)},m(t,n){p(e,t,n),a=!0},p:u,i(t){a||(f(e.$$.fragment,t),a=!0)},o(t){g(e.$$.fragment,t),a=!1},d(t){d(e,t)}}}function j(o,e,a){let{name:t="tezca",imgPath:m="tu2zhong.svg"}=e;const i=[0,5320],l=t==="tezca"?[{"id": "intro", "title": "牛王节", "text": "为耕牛洗浴装扮，停耕喂食，感恩农耕伙伴。<br><br>牛王节主要分布在西南地区。古代农耕社会下，耕牛是重要的生产工具，牛王节源于古代稻作社会对耕牛的保护、尊崇与感恩，对耕牛的保护是农业生产的关键一环。民俗传说中，神牛盗谷种、下凡犁荒，固有农夫在春耕前、秋收后择吉举行节日庆祝，祈牛壮健。牛王节举办日期集中在夏季，以农历四月初八为主。"}, {"id": "colors", "title": "浴牛", "text": "牛王节当天农民会为耕牛洗浴，用木桶或河塘清水冲洗牛身，梳理毛发，护养耕牛。丽江纳西族于牛王节带牛下河，清洗牛脚，去除寄生虫；侗族浴牛节或牵牛下河洗刷，或以羽毛为牛洗尘。"}, {"id": "face", "title": "饰牛", "text": "牛王节农民会为耕牛精心装扮，用五彩糯米花饭、鲜草编成花环戴于牛角，或系上红绸彩带，在牛身上涂抹吉祥图案。部分地区还会给牛佩戴银铃、铜铃，行走时叮当作响。这些装饰既表达对耕牛的崇敬与感恩，也寓意驱邪纳福，祈求牛只健壮、农耕顺利"}, {"id": "spear", "title": "停耕喂牛", "text": "当日让耕牛卸下犁耙休息，禁止役使，以示犒劳。主人以精饲料、糯米饭、甜酒等喂食耕牛，有的还煮鸡蛋、泡米酒敬奉。贵州苗族有\"让牛吃独食\"之说，广西侗族则以百草粽叶包饭饲喂。这一习俗表达了对耕牛终年劳作的感激与体恤。"}]:t==="tezca2"?[{"id": "intro", "title": "二十四节气", "text": "以节气物候指导农事，四时八节农耕周期。<br><br>二十四节气是中国古代订立的一种补充历法，源于黄河流域农耕文明对太阳周年运动的精确观测。它以地球绕太阳公转轨道上的24个等分点为基准，每15°设一节气。该体系融合天文测算、气象观察与农事实践，形成\"节气—物候—农事\"三位一体的精密时间制度。"}, {"id": "colors", "title": "七十二物候", "text": "每节气又分三候，共七十二物候。古人以五日为一候，三候为一气，通过观察动植物变化、自然现象来标记时间流转。如立春三候为\"东风解冻，蛰虫始振，鱼陟负冰\"；惊蛰时\"桃始华，仓庚鸣，鹰化为鸠\"，对农事有重要指导作用。"}, {"id": "face", "title": "四时八节", "text": "二十四节气以\"四时八节\"为骨架，构建全年时序体系。\"四时\"即春夏秋冬四季，每季三月；\"八节\"为立春、春分、立夏、夏至、立秋、秋分、立冬、冬至八个关键节点，标志季节转换与阴阳交替，划定农耕活动的宏观阶段，如\"春生、夏长、秋收、冬藏\"。"}, {"id": "spear", "title": "农事指导", "text": "节气准确反映季节、气候、物候变化，是指导农事活动的操作指南。如\"清明前后，种瓜点豆\"提示播种时机；\"小满不满，麦有一险\"预警灌浆期水肥管理。农民依节气安排耕、种、管、收，顺应天时以获丰收，体现了\"天人合一\"的农耕智慧。"}]:t==="tezca3"?[{"id": "intro", "title": "社日节", "text": "春社祈年秋社报赛，祭祀土地神求丰收。<br><br>社日节，中国传统节日，分春社和秋社。春社在立春后第五个戊日，秋社在立秋后第五个戊日。社日源于古代对土地神（社神）的崇拜，\"社\"即土地神之位。社日节是古代农民祭祀土地神，祈求丰收（春社）和报答神恩（秋社）的重要日子。"}, {"id": "colors", "title": "春社祈年", "text": "春社重在\"祈\"。此时正值春耕开始，农民通过祭祀社神，祈求一年风调雨顺、五谷丰登。仪式包括献祭牲畜、酒食，并举行\"社戏\"等娱乐活动。春社也是人们春游踏青、会饮娱乐的时机，充满生机与希望，体现了对新一年美好生活的向往。"}, {"id": "face", "title": "秋社报赛", "text": "秋社重在\"报\"。此时秋收结束，农民再次祭祀社神，报告一年的收成，感谢土地神的赐予，称为\"春祈秋报\"。秋社仪式隆重，人们献上新收获的谷物瓜果，举行庆祝丰收的宴饮活动，分享劳动果实，洋溢着丰收的喜悦与感恩之情。"}, {"id": "spear", "title": "社戏社饮", "text": "社日节期间，各地会有丰富多彩的民俗活动。\"社戏\"是最为普遍的形式，即在社庙前演戏酬神，同时也娱乐乡邻。\"社饮\"则是社祭后的聚餐，全村人共食祭品，不仅增进邻里感情，也寓意共同分享神的福佑。这些活动增强了社区凝聚力。"}]:s["tezca-steps"];return[i,l,t,m]}class y extends r{constructor(e){super();c(this,e,j,z,i,{name:2,imgPath:3})}}export{y as default};
